var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"시간…… 알 수 없음.","JPN":"時間……不明。","ENG":"Time... Unknown.","TWN":"無法得知……時間。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"위치…… 알 수 없음.","JPN":"場所……不明。","ENG":"Location... Unknown.","TWN":"無法得知……位置。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘도 지원이 오지 않는다.","JPN":"まだ応援はこない。","ENG":"No support came today as well.","TWN":"今天也沒有支援抵達。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만…….","JPN":"だが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"지원이 오기 전까지, 대원들을 지켜야 한다.","JPN":"応援が来るまで、隊員たちを守らなければ。","ENG":"I must protect my squad members until the day support comes.","TWN":"在支援抵達之前，我必須守護隊員們。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음.","JPN":"作戦記録、録音。","ENG":"Operation log.","TWN":"作戰紀錄錄音。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"71회째로 방주의 동결을 해제하려 시도했으나, 실패했다.","JPN":"71回目、箱舟の凍結を解こうとしたが失敗した。","ENG":"Attempt 71 of undoing the Ark's stasis, failed.","TWN":"這是第71次嘗試解凍方舟，再次失敗。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……물자 보급은, 더 이상 연기할 수 없는 상황이다.","JPN":"……物資の補給は、これ以上先延ばしにはできない状況だ。","ENG":"...Supplies are running low. I cannot delay it any longer.","TWN":"……物資補給已經無法再耽延下去。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다행히 이 일대에는 방치된 함선들이 많다.","JPN":"幸い、ここ一帯には放置されている艦船が多い。","ENG":"Luckily, there are many abandoned ships nearby.","TWN":"幸好這附近有許多擱置的艦船。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"눈보라가 약해지는 대로, 함선들을 순회하면서 물자 확보에 나설 계획이다.","JPN":"吹雪の勢いがおさまり次第、艦船を巡回しつつ物資の確保をしようと思う。","ENG":"When the blizzard dies down, I will plan a route to secure supplies from the ships.","TWN":"等暴風雪減弱後，我會去巡視看看裡面有沒有物資。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"첫 번째 함선에선 유의미한 물품을 건지지 못했다.","JPN":"最初の艦船では役立つものは発見できなかった。","ENG":"The first ship did not have any useful supplies.","TWN":"在第一艘艦船中沒有尋獲適合的物資。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다행히 인근에 있던 두 번째 함선에서 전투식량을 소량 발견할 수 있었다.","JPN":"幸運にも近くにあった二隻目の艦船からは戦闘食糧を少量発見することができた。","ENG":"However, I was able to find some combat rations from the second ship in proximity.","TWN":"幸好在附近第二艘艦船中有發現少量的戰鬥物資。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"여기 온 뒤 며칠이 지났는지 정확한 일자는 알 수 없으나……","JPN":"ここに来てから何日経ったのか正確にはわからないが……","ENG":"Although it is unclear how much time has passed since I arrived here...","TWN":"來到這裡後，不知道已經經過幾天……"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"유통기한은 넉넉할 것으로 추정된다.","JPN":"賞味期限はまだ余裕があると思われる。","ENG":"but the expiration date is estimated to be sufficient.","TWN":"不過我想距離有效期限應該還有一段時間。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……어쩐지 입맛이 돌지 않는다. 방주로 돌아가서 섭취하겠다.","JPN":"……どうにも食欲がない。箱舟に帰還してから摂取することにする。","ENG":"...My appetite is gone. I will eat the rest after returning to the Ark.","TWN":"……不知為何沒有胃口，等回到方舟後再進食吧。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"식량 외에도 관리국이 생산한 표준 개인 화기를 발견, 기능 확인 중이다.","JPN":"食料以外にも管理局が生産した標準個人用火器を発見、動作を確認中。","ENG":"Aside from the rations, I found an Administration-issued standard personal firearm. Checking its functionality now.","TWN":"除糧食外，還有發現管理局生產的標準個人武器，功能確認中。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 다니니…… 부전대장이 떠오르는군.","JPN":"こうしていると……副戦隊長を思い出すな。","ENG":"Walking around like this... reminds me of my deputy commander.","TWN":"這樣走著走著……令我想起副戰隊長。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"필요 없어 보이는 잡동사니도 분명 쓸모가 있을 거라며 주워 모았지.","JPN":"不要そうに見えるガラクタでも、きっと使い道があると言って収集していた。","ENG":"She had picked up useless-looking trash, saying that they would be useful one day.","TWN":"明明看起來沒用的雜物，她也要收集起來，說什麼以後一定會用到。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"희한하게도 그 잡동사니들은 어떤 식으로든 사용되었다.","JPN":"不思議なことに、収集したガラクタは何かしらに利用された。","ENG":"Oddly enough, she did find ways to utilize that junk.","TWN":"更厲害的是，之後還真的可以廢物利用。"},"stage":{"bg":"WARZONE_01","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};